mapper.delete:
DELETE FROM TPR701
WHERE FACTORY_CODE     = #{factoryCode}
  AND WORKCENTER_CODE  = #{workcenterCode}
  AND WORK_DATE BETWEEN #{dateFrom} AND #{dateTo}

mapper.select:
SELECT KPI_SEQ kpiSeq, FACTORY_CODE factoryCode, WORKCENTER_CODE workcenterCode, PROCESS_TYPE processType, WORK_DATE workDate, WORK_ORDER_NO workOrderNo, ITEM_NAME itemName, ITEM_CODE itemCode, PROD_QTY prodQty, GOOD_QTY goodQty, BAD_QTY badQty, BAD_RATE badRate, WORK_TIME workTime, QTY_PER_HOUR qtyPerHour, REG_DT regDt, REG_ID regId FROM TPR701 WHERE FACTORY_CODE = #{factoryCode} AND WORK_DATE BETWEEN #{dateFrom} AND #{dateTo}
AND WORKCENTER_CODE = #{workcenterCode}
ORDER BY WORK_DATE ASC, WORKCENTER_CODE ASC, KPI_SEQ ASC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

SELECT COUNT(1)
FROM TPR701
WHERE FACTORY_CODE = #{factoryCode}
  AND WORK_DATE BETWEEN #{dateFrom} AND #{dateTo}

  AND WORKCENTER_CODE = #{workcenterCode}

SELECT WORK_DATE workDate, WORKCENTER_CODE workcenterCode, PROCESS_TYPE processType, SUM(PROD_QTY) totalProdQty, SUM(GOOD_QTY) totalGoodQty, SUM(BAD_QTY) totalBadQty, CASE WHEN SUM(PROD_QTY) = 0 THEN 0 ELSE SUM(BAD_QTY) * 100.0 / SUM(PROD_QTY) END avgBadRate, SUM(WORK_TIME) totalWorkTime, CASE WHEN SUM(WORK_TIME) = 0 THEN 0 ELSE SUM(PROD_QTY) / SUM(WORK_TIME) END avgQtyPerHour, COUNT(1) rowCount FROM TPR701 WHERE FACTORY_CODE = #{factoryCode} AND WORK_DATE BETWEEN #{dateFrom} AND #{dateTo}
AND WORKCENTER_CODE = #{workcenterCode}
GROUP BY WORK_DATE, WORKCENTER_CODE, PROCESS_TYPE ORDER BY WORK_DATE ASC, WORKCENTER_CODE ASC
